<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Falling Sand Sandbox</title>
<style>
  body{margin:0;background:#121212;color:#eee;font-family:sans-serif;display:flex;flex-direction:column;align-items:center;}
  #controls{margin:10px;}
  button{background:#1e88e5;border:none;padding:8px 12px;margin:2px;color:white;border-radius:4px;cursor:pointer;}
  button:hover{background:#1565c0;}
  canvas{border:1px solid #444;background:#000;}
</style>
</head>
<body>
<div id="controls">
  <button id="mat-sand">Sand</button>
  <button id="mat-water">Water</button>
  <button id="mat-wall">Wall</button>
  <button id="mat-acid">Acid</button>
  <button id="mat-empty">Eraser</button>
  <button id="clear">Clear</button>
</div>
<canvas id="sand" width="400" height="400"></canvas>

<script>
(() => {
  const canvas = document.getElementById('sand');
  const ctx = canvas.getContext('2d');
  const w = 80, h = 80; // grid size
  const cellSize = canvas.width / w;
  const materials = ['empty','sand','water','wall','acid'];
  const colors = {
    empty:'#000',
    sand:'#c27b0e',
    water:'#4a90d9',
    wall:'#555',
    acid:'#d32f2f'
  };
  let grid = Array.from({length:h},()=>Array(w).fill('empty'));
  let nextGrid;
  let currentMat = 'sand';
  let painting = false;

  // API
  window.sim = {
    w, h,
    tick(n){ for(let i=0;i<n;i++) step(); draw(); },
    get(x,y){ return grid[y][x]; },
    set(x,y,m){ if(m===undefined) m='empty'; grid[y][x]=m; },
    clear(){ grid.forEach(row=>row.fill('empty')); }
  };

  function step(){
    nextGrid = Array.from({length:h},()=>Array(w).fill('empty'));
    // copy walls and empty to next
    for(let y=0;y<h;y++){
      for(let x=0;x<w;x++){
        if(grid[y][x]==='wall') nextGrid[y][x]='wall';
        else if(grid[y][x]==='empty') nextGrid[y][x]='empty';
      }
    }
    // process bottom-up
    for(let y=h-1;y>=0;y--){
      for(let x=0;x<w;x++){
        const m = grid[y][x];
        if(m==='sand' || m==='water' || m==='acid'){
          let moved=false;
          const belowY=y+1;
          // helper to check bounds
          const inBounds=(xx,yy)=> xx>=0&&xx<w&&yy>=0&&yy<h;
          if(inBounds(x,belowY) && grid[belowY][x]==='empty'){
            nextGrid[belowY][x]=m; moved=true;
          }else if(m==='sand' || m==='acid'){ // swap with water or acid
            if(inBounds(x,belowY) && (grid[belowY][x]==='water'||grid[belowY][x]==='acid')){
              nextGrid[belowY][x]=m; moved=true;
            }
          }else if(m==='sand'){
            const dirs=[-1,1]; // left,right
            dirs.sort(()=>Math.random()-0.5);
            for(const d of dirs){
              const nx=x+d, ny=belowY;
              if(inBounds(nx,ny) && grid[ny][nx]==='empty'){
                nextGrid[ny][nx]=m; moved=true; break;
              }
            }
          }else if(m==='water' || m==='acid'){
            // try horizontal spread
            const dirs=[-1,1];
            dirs.sort(()=>Math.random()-0.5);
            for(const d of dirs){
              const nx=x+d, ny=y;
              if(inBounds(nx,ny) && grid[ny][nx]==='empty'){
                nextGrid[ny][nx]=m; moved=true; break;
              }
            }
          }

          // if not moved, stay
          if(!moved){
            nextGrid[y][x]=m;
          }

          // Acid dissolving
          if(m==='acid'){
            const neigh=[ [0,-1],[0,1],[-1,0],[1,0] ];
            for(const [dx,dy] of neigh){
              const nx=x+dx, ny=y+dy;
              if(inBounds(nx,ny) && (grid[ny][nx]==='sand'||grid[ny][nx]==='wall')){
                nextGrid[ny][nx]='empty';
              }
            }
          }
        }
      }
    }
    grid = nextGrid;
  }

  function draw(){
    for(let y=0;y<h;y++){
      for(let x=0;x<w;x++){
        ctx.fillStyle=colors[grid[y][x]];
        ctx.fillRect(x*cellSize, y*cellSize, cellSize, cellSize);
      }
    }
  }

  // UI
  document.getElementById('mat-sand').onclick(()=>currentMat='sand');
  document.getElementById('mat-water').onclick(()=>currentMat='water');
  document.getElementById('mat-wall').onclick(()=>currentMat='wall');
  document.getElementById('mat-acid').onclick(()=>currentMat='acid');
  document.getElementById('mat-empty').onclick(()=>currentMat='empty');
  document.getElementById('clear').onclick(()=>{ window.sim.clear(); draw(); });

  canvas.addEventListener('mousedown',e=>{ painting=true; paint(e); });
  canvas.addEventListener('mousemove',e=>{ if(painting) paint(e); });
  canvas.addEventListener('mouseup',()=>painting=false);
  canvas.addEventListener('mouseleave',()=>painting=false);

  function paint(e){
    const rect=canvas.getBoundingClientRect();
    const x=Math.floor((e.clientX-rect.left)/cellSize);
    const y=Math.floor((e.clientY-rect.top)/cellSize);
    if(x>=0&&x<w&&y>=0&&y<h){
      window.sim.set(x,y,currentMat);
      draw();
    }
  }

  // animation loop
  function loop(){ step(); draw(); requestAnimationFrame(loop); }
  requestAnimationFrame(loop);
})();
</script>
</body>
</html>
